const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};
module.exports = { sendError };

const express = require('express');
const router = express.Router();
const { getProjects, createProject } = require('./service');
router.get('/', getProjects);
router.post('/', createProject);
module.exports = router;

const { v4: uuidv4 } = require('uuid');
const projects = [];
const getProjects = (req, res) => {
  res.json({ projects });
};
const createProject = (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'BadRequest', 'Name is required');
  const project = { id: uuidv4(), name: req.body.name };
  projects.push(project);
  res.status(201).json({ project });
};
module.exports = { getProjects, createProject };

const express = require('express');
const router = express.Router({ mergeParams: true });
const { updateTaskStatus, getTasksByStatus } = require('./service');
router.patch('/', updateTaskStatus);
router.get('/', getTasksByStatus);
module.exports = router;

const tasks = [];
const updateTaskStatus = (req, res) => {
  const taskIndex = tasks.findIndex(task => task.id === req.params.taskId);
  if (taskIndex === -1) return sendError(res, 404, 'NotFound', 'Task not found');
  tasks[taskIndex].status = req.body.status;
  res.json({ task: tasks[taskIndex] });
};
const getTasksByStatus = (req, res) => {
  const doneTasks = tasks.filter(task => task.status === 'done');
  res.json({ tasks: doneTasks });
};
module.exports = { updateTaskStatus, getTasksByStatus };

